import{_ as a,C as d,o as n,c as s,j as o,a as r,E as c,aA as i,w as l}from"./chunks/framework.CULDwMqt.js";const w=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reference/hill.md","filePath":"reference/hill.md","lastUpdated":null}'),p={name:"reference/hill.md"},h={class:"jldocstring custom-block",open:""};function g(u,e,f,m,y,b){const t=d("Badge");return n(),s("div",null,[o("details",h,[o("summary",null,[e[0]||(e[0]=o("a",{id:"Foresight.hill",href:"#Foresight.hill"},[o("span",{class:"jlbinding"},"Foresight.hill")],-1)),e[1]||(e[1]=r()),c(t,{type:"info",class:"jlObjectType jlFunction",text:"Function"})]),e[3]||(e[3]=i('<div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">hill</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x; kwargs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Plots a density with a transparent fill.</p><p><strong>Key attributes:</strong></p><p><code>color</code> = <code>@inherit patchcolor</code>: Color of the interior fill.</p><p><code>fillalpha</code> = <code>0.5</code>: Transparency of the interior fill.</p><p><code>filternan</code> = <code>true</code>: Whether to remove NaN values from the data before plotting.</p><p><code>strokecolor</code> = <code>automatic</code>: Color of the outline stroke.</p><p><code>strokewidth</code> = <code>1</code>: Width of the outline stroke.</p><p><strong>Plot type</strong></p><p>The plot type alias for the <code>hill</code> function is <code>Hill</code>.</p><p><strong>Attributes</strong></p><p><strong><code>alpha</code></strong> = <code>1.0</code> — The alpha value of the colormap or color attribute. Multiple alphas like in <code>plot(alpha=0.2, color=(:red, 0.5)</code>, will get multiplied.</p><p><strong><code>bandwidth</code></strong> = <code>automatic</code> — Kernel density bandwidth, determined automatically if <code>automatic</code>.</p><p><strong><code>boundary</code></strong> = <code>automatic</code> — Boundary of the density estimation, determined automatically if <code>automatic</code>.</p><p><strong><code>clip_planes</code></strong> = <code>@inherit clip_planes automatic</code> — Clip planes offer a way to do clipping in 3D space. You can set a Vector of up to 8 <code>Plane3f</code> planes here, behind which plots will be clipped (i.e. become invisible). By default clip planes are inherited from the parent plot or scene. You can remove parent <code>clip_planes</code> by passing <code>Plane3f[]</code>.</p><p><strong><code>color</code></strong> = <code>@inherit patchcolor</code> — Color of the density fill</p><p><strong><code>colormap</code></strong> = <code>@inherit colormap :viridis</code> — Sets the colormap that is sampled for numeric <code>color</code>s. <code>PlotUtils.cgrad(...)</code>, <code>Makie.Reverse(any_colormap)</code> can be used as well, or any symbol from ColorBrewer or PlotUtils. To see all available color gradients, you can call <code>Makie.available_gradients()</code>.</p><p><strong><code>colorrange</code></strong> = <code>automatic</code> — The values representing the start and end points of <code>colormap</code>.</p><p><strong><code>colorscale</code></strong> = <code>identity</code> — The color transform function. Can be any function, but only works well together with <code>Colorbar</code> for <code>identity</code>, <code>log</code>, <code>log2</code>, <code>log10</code>, <code>sqrt</code>, <code>logit</code>, <code>Makie.pseudolog10</code>, <code>Makie.Symlog10</code>, <code>Makie.AsinhScale</code>, <code>Makie.SinhScale</code>, <code>Makie.LogScale</code>, <code>Makie.LuptonAsinhScale</code>, and <code>Makie.PowerScale</code>.</p><p><strong><code>cycle</code></strong> = <code>:color =&gt; :patchcolor</code> — <em>No docs available.</em></p><p><strong><code>depth_shift</code></strong> = <code>0.0</code> — Adjusts the depth value of a plot after all other transformations, i.e. in clip space, where <code>-1 &lt;= depth &lt;= 1</code>. This only applies to GLMakie and WGLMakie and can be used to adjust render order (like a tunable overdraw).</p><p><strong><code>direction</code></strong> = <code>:x</code> — The dimension along which the <code>values</code> are distributed. Can be <code>:x</code> or <code>:y</code>.</p><p><strong><code>fillalpha</code></strong> = <code>0.5</code> — Transparency of the fill patch</p><p><strong><code>filternan</code></strong> = <code>true</code> — Whether to remove NaN values</p><p><strong><code>fxaa</code></strong> = <code>true</code> — Adjusts whether the plot is rendered with fxaa (fast approximate anti-aliasing, GLMakie only). Note that some plots implement a better native anti-aliasing solution (scatter, text, lines). For them <code>fxaa = true</code> generally lowers quality. Plots that show smoothly interpolated data (e.g. image, surface) may also degrade in quality as <code>fxaa = true</code> can cause blurring.</p><p><strong><code>highclip</code></strong> = <code>automatic</code> — The color for any value above the colorrange.</p><p><strong><code>inspectable</code></strong> = <code>@inherit inspectable</code> — Sets whether this plot should be seen by <code>DataInspector</code>. The default depends on the theme of the parent scene.</p><p><strong><code>inspector_clear</code></strong> = <code>automatic</code> — Sets a callback function <code>(inspector, plot) -&gt; ...</code> for cleaning up custom indicators in DataInspector.</p><p><strong><code>inspector_hover</code></strong> = <code>automatic</code> — Sets a callback function <code>(inspector, plot, index) -&gt; ...</code> which replaces the default <code>show_data</code> methods.</p><p><strong><code>inspector_label</code></strong> = <code>automatic</code> — Sets a callback function <code>(plot, index, position) -&gt; string</code> which replaces the default label generated by DataInspector.</p><p><strong><code>linestyle</code></strong> = <code>nothing</code> — Sets the line pattern of the density outline.</p><p><strong><code>lowclip</code></strong> = <code>automatic</code> — The color for any value below the colorrange.</p><p><strong><code>model</code></strong> = <code>automatic</code> — Sets a model matrix for the plot. This overrides adjustments made with <code>translate!</code>, <code>rotate!</code> and <code>scale!</code>.</p><p><strong><code>nan_color</code></strong> = <code>:transparent</code> — The color for NaN values.</p><p><strong><code>npoints</code></strong> = <code>200</code> — The resolution of the estimated curve along the dimension set in <code>direction</code>.</p><p><strong><code>offset</code></strong> = <code>0.0</code> — Shift the density baseline, for layering multiple densities on top of each other.</p><p><strong><code>overdraw</code></strong> = <code>false</code> — Controls if the plot will draw over other plots. This specifically means ignoring depth checks in GL backends</p><p><strong><code>space</code></strong> = <code>:data</code> — Sets the transformation space for box encompassing the plot. See <code>Makie.spaces()</code> for possible inputs.</p><p><strong><code>ssao</code></strong> = <code>false</code> — Adjusts whether the plot is rendered with ssao (screen space ambient occlusion). Note that this only makes sense in 3D plots and is only applicable with <code>fxaa = true</code>.</p><p><strong><code>strokearound</code></strong> = <code>false</code> — Controls whether the outline only draws around the complete density (true) or just the maximum values (false).</p><p><strong><code>strokecolor</code></strong> = <code>automatic</code> — Color of the density stroke</p><p><strong><code>strokewidth</code></strong> = <code>@inherit linewidth</code> — <em>No docs available.</em></p><p><strong><code>transformation</code></strong> = <code>:automatic</code> — Controls the inheritance or directly sets the transformations of a plot. Transformations include the transform function and model matrix as generated by <code>translate!(...)</code>, <code>scale!(...)</code> and <code>rotate!(...)</code>. They can be set directly by passing a <code>Transformation()</code> object or inherited from the parent plot or scene. Inheritance options include:</p><ul><li><p><code>:automatic</code>: Inherit transformations if the parent and child <code>space</code> is compatible</p></li><li><p><code>:inherit</code>: Inherit transformations</p></li><li><p><code>:inherit_model</code>: Inherit only model transformations</p></li><li><p><code>:inherit_transform_func</code>: Inherit only the transform function</p></li><li><p><code>:nothing</code>: Inherit neither, fully disconnecting the child&#39;s transformations from the parent</p></li></ul><p>Another option is to pass arguments to the <code>transform!()</code> function which then get applied to the plot. For example <code>transformation = (:xz, 1.0)</code> which rotates the <code>xy</code> plane to the <code>xz</code> plane and translates by <code>1.0</code>. For this inheritance defaults to <code>:automatic</code> but can also be set through e.g. <code>(:nothing, (:xz, 1.0))</code>.</p><p><strong><code>transparency</code></strong> = <code>false</code> — Adjusts how the plot deals with transparency. In GLMakie <code>transparency = true</code> results in using Order Independent Transparency.</p><p><strong><code>visible</code></strong> = <code>true</code> — Controls whether the plot gets rendered or not.</p><p><strong><code>weights</code></strong> = <code>automatic</code> — Assign a vector of statistical weights to <code>values</code>.</p>',48)),c(t,{type:"info",class:"source-link",text:"source"},{default:l(()=>[...e[2]||(e[2]=[o("a",{href:"https://github.com/MakieOrg/Makie.jl/blob/v0.24.9/src/recipes.jl#L540-L659",target:"_blank",rel:"noreferrer"},"source",-1)])]),_:1})])])}const v=a(p,[["render",g]]);export{w as __pageData,v as default};
